'use client';

import React, { useState, useCallback } from 'react';
import { DropZone } from '@/components/ui/DropZone';
import { Button } from '@/components/ui/Button';
import { Card } from '@/components/ui/Card';
import { ProgressBar } from '@/components/ui/ProgressBar';
import { useFileProcessing } from '@/hooks/useFileProcessing';
import { useCompressionHistory } from '@/hooks/useCompressionHistory';
import { useToast } from '@/hooks/useToast';
import { mergePDFs } from '@/lib/pdf-processing';
import { downloadBlob, formatBytes } from '@/lib/utils';
import { Combine, Download, GripVertical, X } from 'lucide-react';
import {
  DndContext,
    closestCenter,
      KeyboardSensor,
        PointerSensor,
          useSensor,
            useSensors,
              DragEndEvent,
              } from '@dnd-kit/core';
              import {
                arrayMove,
                  SortableContext,
                    sortableKeyboardCoordinates,
                      useSortable,
                        verticalListSortingStrategy,
                        } from '@dnd-kit/sortable';
                        import { CSS } from '@dnd-kit/utilities';

                        function SortableFileItem({
                          file,
                            index,
                              onRemove,
                              }: {
                                file: { id: string; name: string; size: number };
                                  index: number;
                                    onRemove: (id: string) => void;
                                    }) {
                                      const {
                                          attributes,
                                              listeners,
                                                  setNodeRef,
                                                      transform,
                                                          transition,
                                                              isDragging,
                                                                } = useSortable({ id: file.id });

                                                                  const style = {
                                                                      transform: CSS.Transform.toString(transform),
                                                                          transition,
                                                                            };

                                                                              return (
                                                                                  <div
                                                                                        ref={setNodeRef}
                                                                                              style={style}
                                                                                                    className={`flex items-center gap-3 p-3 bg-gray-50 dark:bg-gray-800 rounded-lg ${
                                                                                                            isDragging ? 'opacity-50 shadow-lg' : ''
                                                                                                                  }`}
                                                                                                                      >
                                                                                                                            <button {...attributes} {...listeners} className="cursor-grab">
                                                                                                                                    <GripVertical className="w-4 h-4 text-gray-400" />
                                                                                                                                          </button>
                                                                                                                                                <span className="w-6 h-6 bg-primary-100 dark:bg-primary-900/30 rounded flex items-center justify-center text-xs font-medium text-primary-600 dark:text-primary-400">
                                                                                                                                                        {index + 1}
                                                                                                                                                              </span>
                                                                                                                                                                    <div className="flex-1 min-w-0">
                                                                                                                                                                            <p className="text-sm font-medium text-gray-900 dark:text-white truncate">
                                                                                                                                                                                      {file.name}
                                                                                                                                                                                              </p>
                                                                                                                                                                                                      <p className="text-xs text-gray-500 dark:text-gray-400">
                                                                                                                                                                                                                {formatBytes(file.size)}
                                                                                                                                                                                                                        </p>
                                                                                                                                                                                                                              </div>
                                                                                                                                                                                                                                    <Button variant="ghost" size="sm" onClick={() => onRemove(file.id)}>
                                                                                                                                                                                                                                            <X className="w-4 h-4" />
                                                                                                                                                                                                                                                  </Button>
                                                                                                                                                                                                                                                      </div>
                                                                                                                                                                                                                                                        );
                                                                                                                                                                                                                                                        }

                                                                                                                                                                                                                                                        export function PdfMerger() {
                                                                                                                                                                                                                                                          const [fileOrder, setFileOrder] = useState<string[]>([]);
                                                                                                                                                                                                                                                            const [isMerging, setIsMerging] = useState(false);
                                                                                                                                                                                                                                                              const [mergedPdf, setMergedPdf] = useState<Blob | null>(null);
                                                                                                                                                                                                                                                                
                                                                                                                                                                                                                                                                  const { addToHistory } = useCompressionHistory();
                                                                                                                                                                                                                                                                    const { showSuccess, showError } = useToast();
                                                                                                                                                                                                                                                                      const { files, addFiles, removeFile, clearFiles } = useFileProcessing({
                                                                                                                                                                                                                                                                          maxFiles: 20,
                                                                                                                                                                                                                                                                              maxSize: 100 * 1024 * 1024,
                                                                                                                                                                                                                                                                                  acceptedTypes: ['application/pdf'],
                                                                                                                                                                                                                                                                                    });

                                                                                                                                                                                                                                                                                      const sensors = useSensors(
                                                                                                                                                                                                                                                                                          useSensor(PointerSensor),
                                                                                                                                                                                                                                                                                              useSensor(KeyboardSensor, {
                                                                                                                                                                                                                                                                                                    coordinateGetter: sortableKeyboardCoordinates,
                                                                                                                                                                                                                                                                                                        })
                                                                                                                                                                                                                                                                                                          );

                                                                                                                                                                                                                                                                                                            const handleDragEnd = (event: DragEndEvent) => {
                                                                                                                                                                                                                                                                                                                const { active, over } = event;
                                                                                                                                                                                                                                                                                                                    if (over && active.id !== over.id) {
                                                                                                                                                                                                                                                                                                                          const oldIndex = fileOrder.indexOf(active.id as string);
                                                                                                                                                                                                                                                                                                                                const newIndex = fileOrder.indexOf(over.id as string);
                                                                                                                                                                                                                                                                                                                                      setFileOrder(arrayMove(fileOrder, oldIndex, newIndex));
                                                                                                                                                                                                                                                                                                                                          }
                                                                                                                                                                                                                                                                                                                                            };

                                                                                                                                                                                                                                                                                                                                              const handleAddFiles = useCallback(
                                                                                                                                                                                                                                                                                                                                                  (newFiles: File[]) => {
                                                                                                                                                                                                                                                                                                                                                        addFiles(newFiles);
                                                                                                                                                                                                                                                                                                                                                              setFileOrder((prev) => [
                                                                                                                                                                                                                                                                                                                                                                      ...prev,
                                                                                                                                                                                                                                                                                                                                                                              ...newFiles.map((_, i) => `file-${Date.now()}-${i}`),
                                                                                                                                                                                                                                                                                                                                                                                    ]);
                                                                                                                                                                                                                                                                                                                                                                                        },
                                                                                                                                                                                                                                                                                                                                                                                            [addFiles]
                                                                                                                                                                                                                                                                                                                                                                                              );

                                                                                                                                                                                                                                                                                                                                                                                                const handleMerge = async () => {
                                                                                                                                                                                                                                                                                                                                                                                                    if (files.length < 2) {
                                                                                                                                                                                                                                                                                                                                                                                                          showError('Please add at least 2 PDF files to merge');
                                                                                                                                                                                                                                                                                                                                                                                                                return;
                                                                                                                                                                                                                                                                                                                                                                                                                    }

                                                                                                                                                                                                                                                                                                                                                                                                                        setIsMerging(true);
                                                                                                                                                                                                                                                                                                                                                                                                                            try {
                                                                                                                                                                                                                                                                                                                                                                                                                                  const pdfFiles = files.map((f) => f.file);
                                                                                                                                                                                                                                                                                                                                                                                                                                        const merged = await mergePDFs(pdfFiles);
                                                                                                                                                                                                                                                                                                                                                                                                                                              const blob = new Blob([new Uint8Array(merged) as unknown as BlobPart], { type: 'application/pdf' });
                                                                                                                                                                                                                                                                                                                                                                                                                                                    setMergedPdf(blob);

                                                                                                                                                                                                                                                                                                                                                                                                                                                          addToHistory({
                                                                                                                                                                                                                                                                                                                                                                                                                                                                  toolId: 'merge-pdf',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                          toolName: 'Merge PDF',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  filesProcessed: files.length,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          spaceSaved: 0,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  timestamp: Date.now(),
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        });

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              showSuccess(`Successfully merged ${files.length} PDFs`);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  } catch (error) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        showError('Failed to merge PDFs. Please try again.');
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            } finally {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  setIsMerging(false);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        };

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          const handleDownload = () => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              if (mergedPdf) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    downloadBlob(mergedPdf, 'merged_document.pdf');
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          showSuccess('PDF downloaded');
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                };

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  return (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <div className="space-y-6">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <DropZone
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    onFilesSelected={handleAddFiles}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            acceptedTypes={{ 'application/pdf': ['.pdf'] }}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    maxFiles={20}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          />

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                {files.length > 0 && (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <Card>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <h3 className="font-semibold text-gray-900 dark:text-white mb-4">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              Arrange PDF Order
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        </h3>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <p className="text-sm text-gray-500 dark:text-gray-400 mb-4">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              Drag and drop to rearrange the order of PDFs. Files will be merged in
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          the displayed order.
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    </p>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <DndContext
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    sensors={sensors}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                collisionDetection={closestCenter}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            onDragEnd={handleDragEnd}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      >
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <SortableContext
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                items={files.map((f) => f.id)}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              strategy={verticalListSortingStrategy}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          >
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <div className="space-y-2">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        {files.map((file, index) => (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <SortableFileItem
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              key={file.id}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  file={{
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        id: file.id,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              name: file.name,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    size: file.size,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        }}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            index={index}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                onRemove={removeFile}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  ))}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            </SortableContext>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      </DndContext>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <div className="flex gap-3 mt-6">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <Button
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          onClick={handleMerge}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        disabled={files.length < 2 || isMerging}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      loading={isMerging}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    icon={<Combine className="w-5 h-5" />}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                >
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              Merge {files.length} PDFs
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          </Button>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      {mergedPdf && (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <Button
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    variant="secondary"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    onClick={handleDownload}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    icon={<Download className="w-5 h-5" />}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  >
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  Download Merged PDF
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                </Button>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            )}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              </Card>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    )}

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          {isMerging && (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <ProgressBar
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            indeterminate
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      label="Merging PDFs..."
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    )}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          );
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          }